LGameLanguage.CONF_DEFAULT_PATH = "datal."
LGameLanguage.CONF_DEFAULT_IOS_PATH = "datal_ios."
LGameLanguage.CONF_ROOT_PATH = "datal."

LGameLanguage.LANGUAGE_ENUM_CHINA = "zh"
LGameLanguage.LANGUAGE_ENUM_CHINA_TW = "zhtw"
LGameLanguage.LANGUAGE_ENUM_ENGLISH = "en"
LGameLanguage.LANGUAGE_ENUM_JAPAN = "ja"
LGameLanguage.LANGUAGE_ENUM_VIE = "vie"
LGameLanguage.LANGUAGE_ENUM_RU = "ru"

LGameLanguage.DEFAULT_LANG = "zhtw"

local LanguagePrefabFindRef = LxRequireWithoutReload(LGameLanguage.CONF_DEFAULT_PATH .. "MulLanguagePrefabFindRef")
local LanguagePrefabRef = LxRequireWithoutReload(LGameLanguage.CONF_DEFAULT_PATH .. "MulLanguagePrefabRef")
local LanguageResRef = LxRequireWithoutReload(LGameLanguage.CONF_DEFAULT_PATH .. "MulLanguageResRef")
local LanguageConfRef = LxRequireWithoutReload(LGameLanguage.CONF_DEFAULT_PATH .. "MulLanguageConfRef")
local LanguageAudioRef = LxRequireWithoutReload(LGameLanguage.CONF_DEFAULT_PATH .. "MulLanguageAudioRef")
local LanguageFontRef = LxRequireWithoutReload(LGameLanguage.CONF_DEFAULT_PATH .. "MulLanguageFontRef")
local LanguageShowRef = LxRequireWithoutReload(LGameLanguage.CONF_DEFAULT_PATH .. "MulLanguageShowRef")
local LanguageOtherAudioRef = LxRequireWithoutReload(LGameLanguage.CONF_DEFAULT_PATH .. "MulLanguageOtherAudioRef")
local LanguageTextRef = LxRequireWithoutReload(LGameLanguage.CONF_DEFAULT_PATH .. "MulLanguageTextRef")
local IosVerifyRef = nil
local SensitiveConfRef = nil
local ShieldResRef = nil

------------------------------------------------------------------
function LGameLanguage:Initialize()
	LxBaseMgr.Initialize(self)
	self._isSensitive = false
end

function LGameLanguage:Dispose()
	LxBaseMgr.Dispose(self)
end

function LGameLanguage:DoAfterInitialize()
	self:InitSysLanguageFlag()
end

------------------------------------------------------------------
function LGameLanguage:InitSysLanguageFlag()
	if LGameSettings.platformRegion == 0 or LGameSettings.platformRegion == 1 then
		gLGameI18n:SetLng(self:GetLanguageFlag())
		gLGameI18n:LoadLng()
		return
	end
    local lngSysFlag = LPlayerPrefs.lngSysFlag or ""
	local sysFlag = LNativeHelper.GetPreferredLanguage() or ""

    lngSysFlag = string.lower(lngSysFlag)
    sysFlag = string.lower(sysFlag)

    if lngSysFlag ~= sysFlag then
        lngSysFlag = sysFlag
		LPlayerPrefs.SetLngSysFlag(lngSysFlag)
        local langSysPrefix = lngSysFlag
        if string.len(langSysPrefix) > 2 then
            langSysPrefix = string.sub(langSysPrefix, 1, 2)
        end
        if not string.isempty(lngSysFlag) then
            local findPrefixRef = nil
            local findFlagRef = nil
            for refId, ref in pairs(GameTable.MulLanguageEnumRef) do
                if ref.type == 1 and langSysPrefix == refId then
                    findPrefixRef = ref
                elseif ref.type == 2 and lngSysFlag == refId then
                    findFlagRef = ref
                end
                if findPrefixRef ~= nil and findFlagRef ~= nil then
                    break
                end
            end

            local lngFlag = self:GetLanguageFlag()
            if findFlagRef then
                lngFlag = findFlagRef.lanRes
            elseif findPrefixRef then
                lngFlag = findPrefixRef.lanRes
            end

    
            -- 显示的语言才可以选择,否则还是默认包里的
            if not self:IsInLanguageRef(lngFlag) then
                lngFlag = self:GetLanguageDefaultFlag()
            end

            self:SetLanguageFlag(lngFlag)
        end
    end

    --若没有对应语言配置,则再选择配置的默认语言
    local lngFlag = self:GetLanguageFlag()
    if not self:IsInLanguageRef(lngFlag) then
        lngFlag = self:GetInitialLanguageRefId()
        self:SetLanguageFlag(lngFlag)
    end
    gLGameI18n:SetLng(self:GetLanguageFlag())
    gLGameI18n:LoadLng()
end

-- true: 语言存在于配置文件中
function LGameLanguage:IsInLanguageRef(lngFlag)
    local list = self:GetShowLanguageList()
    for _, v in ipairs(list) do
        if v.refId == lngFlag then
            return true
        end
    end
    return false
end

function LGameLanguage:InitLanguageTextRef()

    local refList = {}
    for refId, ref in pairs(GameTable.MulLanguageTextRef) do
        local wndName = ref.wndName
        if not refList[wndName] then
            refList[wndName] = {}
        end
        table.insert(refList[wndName], ref)
    end

    self._languageTextRefList = refList
end

function LGameLanguage:SetLanguageFlag(lngFlag)
    if LOG_INFO_ENABLED then
        LogWarn("设置当前语言为:" .. lngFlag)
    end
    LPlayerPrefs.SetLngFlag(lngFlag)
end

function LGameLanguage:GetLanguageFlag()
    return LPlayerPrefs.lngFlag
end

function LGameLanguage:GetLanguageDefaultFlag()
    return LGameSettings.platformDefaultLng
end

function LGameLanguage:GetShowLanguageList()
    local refList = self:GetLanguageShowRef()
    local list = {}
    for k, v in pairs(refList) do
        local refId = v.refId
        local packId = v.packId or ""
        if packId == "" then
            table.insert(list, {
                refId = refId,
                name = v.name,
                icon = v.icon,
                sort = v.sort,
            })
        else
            local pack = string.split(packId, ";")
            for kk, vv in pairs(pack) do
                if tonumber(vv) == LGameSettings.platformId then
                    table.insert(list, {
                        refId = refId,
                        name = v.name,
                        icon = v.icon,
                        sort = v.sort,
                    })
                    break
                end
            end
        end
        --if lngList[refId] then

        --end
    end

    table.sort(list, function(a, b)
        if a.sort and b.sort then
            return a.sort < b.sort
        else
            return false
        end
    end)

    return list
end

function LGameLanguage:GetInitialLanguageRefId()
    local refList = self:GetLanguageShowRef()
    for k, v in pairs(refList) do
        local initial = v.initial
        if initial == 1 then
            return v.refId
        end
    end

    if self:IsForeignRegion() then
        return "enus"
    else
        return "zhcn"
    end
end

function LGameLanguage:GetOtherAudioFlag()
    return LPlayerPrefs.otherAudioFlag
end
