function LGameLanguage:VerifyIos(tableName)
    if not IosVerifyRef then
        IosVerifyRef = LxRequireWithoutReload(LGameLanguage.CONF_DEFAULT_PATH .. "IosApproveRef")
    end
    local ref = IosVerifyRef[tableName]
    if ref and ref.ios > 0 then
        return true
    end
    return false
end

function LGameLanguage:GetIosPath(confClassName)
    return LGameLanguage.CONF_DEFAULT_IOS_PATH .. confClassName
end

function LGameLanguage:GetSensitiveTableName(tableName)
    if not SensitiveConfRef then
        SensitiveConfRef = LxRequireWithoutReload(LGameLanguage.CONF_DEFAULT_PATH .. "FilterConfRef")
    end
    local ref = SensitiveConfRef[tableName]
    if ref then
        local conf = ref.replaceConf
        if not string.isempty(conf) then
            return conf
        end
    end
    return tableName
end

function LGameLanguage:SetSensitive(bSensitive)
    self._isSensitive = bSensitive
end

function LGameLanguage:GetConfPath(confClassName)
    local langConfRef = LanguageConfRef[confClassName]
    if langConfRef then
        local lngFlag = self:GetLanguageFlag()
        local lngConfPath = langConfRef[lngFlag]
        if not string.isempty(lngConfPath) then
            return LGameLanguage.CONF_ROOT_PATH .. string.gsub(lngConfPath, '/', '.')
        end
    end

    return LGameLanguage.CONF_DEFAULT_PATH .. confClassName
end

--提审路径
function LGameLanguage:CheckExaIosPath(confClassName)
    if PRODUCT_G_VER and PRODUCT_G_VER ~= 0 then
        return LGameLanguage.CONF_DEFAULT_IOS_PATH .. confClassName
    end

    return nil
end

function LGameLanguage:GetAudioName(audioName)
    if LanguageOtherAudioRef then
        local otherAudioFlag = self:GetOtherAudioFlag()
        if otherAudioFlag == "1" then
            local otherLngAudioRef = LanguageOtherAudioRef[audioName]
            if otherLngAudioRef then
                local otherAudioName = otherLngAudioRef[self:GetLanguageFlag() or ""]
                if not string.isempty(otherAudioName) then
                    return otherAudioName
                end
            end
        end
    end

    local langAudioRef = LanguageAudioRef[audioName]
    if not langAudioRef then
        return audioName
    end

    local lngFlag
    local lngAudioName
    if LGameSettings.platformRegion == LRegionConst.CHINA then
        --国内统一中文语言
        lngFlag = "zhcn"
    elseif LGameSettings.platformRegion == LRegionConst.HMT then
        lngFlag = self:GetLanguageFlag()
    else
        lngFlag = self:GetLanguageFlag()
        lngAudioName = langAudioRef[lngFlag]
        if not lngAudioName or not gLGameLanguage:IsForeignVersion() then
            --若没有对应语言资源，默认英语
            --海外中文依旧用英文语言
            lngFlag = "enus"
        end
    end

    lngAudioName = langAudioRef[lngFlag]
    if not string.isempty(lngAudioName) then
        return lngAudioName
    else
        return audioName
    end
end

function LGameLanguage:GetFontName(fontName)
    local langFontRef = LanguageFontRef[fontName]
    if not langFontRef then
        return fontName
    end

    local lngFlag = self:GetLanguageFlag()
    local lngFlagKey = self:ShiftFontFlagKeyByRegion(lngFlag)

    local lngFontName = langFontRef[lngFlagKey]
    if not string.isempty(lngFontName) then
        return lngFontName
    else
        return fontName
    end
end

function LGameLanguage:GetFontPathByFontName(fontName)
    local langFontRef = LanguageFontRef[fontName]

    local lngFlag = self:GetLanguageFlag()
    local lngFlagKey = self:ShiftFontFlagKeyByRegion(lngFlag)

    local lngFontName = ""
    if langFontRef then
        lngFontName = langFontRef[lngFlagKey] or ""
    else
        for k, v in pairs(LanguageFontRef) do
            local tempLngFontName = v[lngFlagKey]
            if not string.isempty(tempLngFontName)
                    and (string.find(tempLngFontName, fontName)
                    or string.match(tempLngFontName, ".+/(.+)") == fontName) then
                lngFontName = tempLngFontName
                break
            end
        end
    end

    local fontPath = string.match(lngFontName, "(.+)/.+")
    return fontPath or ""
end

---@return V_ShieldResRef
function LGameLanguage:GetShieldResRef(assetName)
    if not ShieldResRef then
        ShieldResRef = LxRequireWithoutReload(LGameLanguage.CONF_DEFAULT_PATH .. "FilterResRef")
    end
    return ShieldResRef[assetName]
end

function LGameLanguage:GetSensitiveResName(assetName)
    local ref = self:GetShieldResRef(assetName)
    if ref then
        local resType = LPlayerPrefs.GetLocalization()
        if resType then
            if resType == 2 then
                local useRes = false
                if PRODUCT_G_VER and PRODUCT_G_VER ~= 0 then
                    useRes = true
                else
                    --- 发行反馈，这个功能是内部使用的，不希望玩家切换到第3套资源
                    local packageId = gLSdkImpl:CallMethod(LSdkMethod.GetSdkPackageId) or "0"
                    packageId = checknumber(packageId)
                    if packageId == 104 then
                        useRes = true
                    end
                end
                if useRes then
                    local replaceRes1 = ref.replaceRes1
                    if not string.isempty(replaceRes1) then
                        return replaceRes1
                    end
                end
            elseif resType == 3 then
                local replaceRes2 = ref.replaceRes2
                if not string.isempty(replaceRes2) then
                    return replaceRes2
                end
            elseif resType == 4 then
                local replaceRes3 = ref.replaceRes3
                if not string.isempty(replaceRes3) then
                    return replaceRes3
                end
            elseif resType == 5 then
                local replaceRes4 = ref.replaceRes4
                if not string.isempty(replaceRes4) then
                    return replaceRes4
                end
            end
        end
        local newAssetName = ref.replaceRes
        if not string.isempty(newAssetName) then
            return newAssetName
        end
    end
    return assetName
end

function LGameLanguage:IsForceSensitiveRes()
    local isOpen = gLGameLogin and gLGameLogin:IsOpenHarmonious()
    local isSet = LPlayerPrefs.GetIsForceSensitiveRes() > 0
    return isOpen or isSet
end

function LGameLanguage:GetResName(assetName)
    if self._isSensitive or self:IsForceSensitiveRes() then
        assetName = self:GetSensitiveResName(assetName)
    end

    local langResRef = LanguageResRef[assetName]
    if not langResRef then
        return assetName, false
    end

    local lngFlag = self:GetLanguageFlag()
    local lngResName = langResRef[lngFlag]
    if not string.isempty(lngResName) then
        local nativeSize = tonumber(langResRef.isNativeSize) or 0
        return lngResName, (nativeSize == 1)
    else
        return assetName, false
    end
end

function LGameLanguage:IsAniSensitive(prefabName)
    local resType = LPlayerPrefs.GetLocalization()
    if resType == 3 and GameTable.ThreeFilterActionRef then
        local ref = GameTable.ThreeFilterActionRef[prefabName]
        if ref then
            return true
        end
    end
    if not self._isSensitive and not self:IsForceSensitiveRes() then
        return false
    end
    local ref = GameTable.FilterHeroRef[prefabName]
    if not ref then
        return false
    end
    return true
end

function LGameLanguage:GetPrefabName(prefabName)
    if self._isSensitive or self:IsForceSensitiveRes() then
        prefabName = self:GetSensitiveResName(prefabName)
    end

    local langPrefabRef = LanguagePrefabRef[prefabName]
    if not langPrefabRef then
        return prefabName
    end

    local lngFlag = self:GetLanguageFlag()
    local lngPrefabName = langPrefabRef[lngFlag]
    if not string.isempty(lngPrefabName) then
        return lngPrefabName
    else
        return prefabName
    end
end

-- 强制替换 spine 资源
function LGameLanguage:GetForcePrefabName(prefabName)
    -- 直接通过评比表，强制替换成 replaceRes2 资源
    local ref = self:GetShieldResRef(prefabName)
    if ref then
        local replaceRes2 = ref.replaceRes2
        if not string.isempty(replaceRes2) then
            prefabName = replaceRes2
        end
    end

    local langPrefabRef = LanguagePrefabRef[prefabName]
    if not langPrefabRef then
        return prefabName
    end

    local lngFlag = self:GetLanguageFlag()
    local lngPrefabName = langPrefabRef[lngFlag]
    if not string.isempty(lngPrefabName) then
        return lngPrefabName
    else
        return prefabName
    end
end


