--获取随机名字的枚举，根据地区判断
function LGameLanguage:GetRandomNameFlag()
    local refIndex
    if LGameSettings.platformRegion == LRegionConst.CHINA then
        --国内统一随机中文名
        refIndex = LGameLanguage.LANGUAGE_ENUM_CHINA
    elseif LGameSettings.platformRegion == LRegionConst.HMT then
        refIndex = LGameLanguage.LANGUAGE_ENUM_CHINA_TW
    elseif LGameSettings.platformRegion == LRegionConst.JAPAN then
        refIndex = LGameLanguage.LANGUAGE_ENUM_JAPAN
    elseif LGameSettings.platformRegion == LRegionConst.RUS then
        refIndex = LGameLanguage.LANGUAGE_ENUM_RU
    else
        --海外统一随机英文名
        refIndex = LGameLanguage.LANGUAGE_ENUM_ENGLISH
    end

    local ref = GameTable.MulLanguageEnumRef[refIndex]
    if not ref then
        return self:GetLanguageFlag()
    end

    return ref.lanRes
end

function LGameLanguage:GetTextRefByWndName(wndName)
    if not self._languageTextRefList then
        self:InitLanguageTextRef()
    end

    return self._languageTextRefList[wndName]
end

function LGameLanguage:ShiftFontFlagKeyByRegion(flagKey)
    if LGameSettings.platformRegion ~= LRegionConst.HMT then
        if flagKey == "zhtw" then
            return "ovezhtw" --海外繁体中文用
        end
    end

    return flagKey
end

function LGameLanguage:IsAutoLanguage(wndName)
    if not self._wndPrefabFindMap then
        self:InitPrefabConfig()
    end
    return (self._wndPrefabFindMap[wndName] ~= nil)
end

function LGameLanguage:InitPrefabConfig()
    self._wndNodeFindMap = {}
    self._wndPrefabFindMap = {}
    for idx, wndNodeItem in pairs(LanguagePrefabFindRef) do
        local wndName = wndNodeItem.wndName
        local uiPath = wndNodeItem.uiPath
        if string.isempty(uiPath) then
            self._wndPrefabFindMap[wndName] = wndName
        else
            local wndNodes = self._wndNodeFindMap[wndName] or {}
            table.insert(wndNodes, wndNodeItem)
            self._wndNodeFindMap[wndName] = wndNodes
            self._wndPrefabFindMap[wndName] = wndName
        end
    end
end

function LGameLanguage:GetWndLanguageNodes(wndName)
    if not self._wndNodeFindMap then
        self:InitPrefabConfig()
    end
    return self._wndNodeFindMap[wndName]
end

