--region 处理提审分包的信息 --------------------------------------------------------------------------------
function LGameLanguage:GetPackProductInfo()
    if self:CheckIsUseSpecialProduct() then
        local platformCfgInfo = self._platformCfgInfo
        --获取字段解析
        if not platformCfgInfo then
            platformCfgInfo = {}
            --初始化配表
            --直接解析三个包的部分
            for i = 1, 3 do
                local pack = GameTable.SdkInfoConfigRef["Pack" .. i]
                if not string.isempty(pack) then
                    local platId = string.split(pack, ";")
                    local tempPlatformCfgInfo = platformCfgInfo[i]
                    if not tempPlatformCfgInfo then
                        tempPlatformCfgInfo = {}
                        platformCfgInfo[i] = tempPlatformCfgInfo
                    end
                    for k, v in ipairs(platId) do
                        tempPlatformCfgInfo[tonumber(v)] = 1
                    end
                end
            end
            self._platformCfgInfo = platformCfgInfo
        end
        --check LGameSettings.platformId
        local platformId = LGameSettings.platformId
        for i = 1, 3 do
            local tempPlatformCfgInfo = platformCfgInfo[i]
            if tempPlatformCfgInfo then
                local tempvalue = tempPlatformCfgInfo[platformId]
                if tempvalue and tempvalue > 0 then
                    return i
                end
            end
        end

        --无结果返回1包
        return 1
    else
        --非sea地区 1包 
        return 1
    end
end
function LGameLanguage:CheckIsUseSpecialProduct()
    --检查区域     LGameSettings.platformRegion
    local version = GameTable.SdkInfoConfigRef["version"]
    version = string.split(version, "|")
    for k, v in ipairs(version) do
        if LGameSettings.platformRegion == checknumber(v) then
            return true
        end
    end
end
function LGameLanguage:GetMainCityBottomShowOrHide(packId)
    local mainCityBottomInfo = self._mainCityBottomInfo
    if not mainCityBottomInfo then
        mainCityBottomInfo = {}
        self._mainCityBottomInfo = mainCityBottomInfo
    end
    if not mainCityBottomInfo[packId] then
        local tempTable = {}
        local info = GameTable.SdkInfoConfigRef["btnList" .. packId]
        info = string.split(info, ";")
        for k, v in ipairs(info) do
            local data = string.split(v, "=")
            tempTable[k] = {
                index = checknumber(data[1]),
                icon = data[2],
                btnName = data[3],
                isShow = checknumber(data[4]) == 1,
            }
        end
        mainCityBottomInfo[packId] = tempTable
    end
    return mainCityBottomInfo[packId]
end

function LGameLanguage:GetMainCityAllBottomShowOrHide(packId)
    local info = GameTable.SdkInfoConfigRef["isMainBottom" .. packId] or 0
    return checknumber(info) == 1
end

