--账号绑定使用
function LGameLanguage:CheckIsCanGoogleBindAccount()
    local checkPack = checknumber(LGameSettings.platformId)
    if checkPack == 205 then
        if gLGameLanguage:IsAmericaRegion() then
            return false
        end
    end
    return true
end

function LGameLanguage:CheckIsOnlyEmailBindAccount()
    local checkPack = checknumber(LGameSettings.platformId)
    if checkPack == 203 then
        if gLGameLanguage:IsAmericaRegion() then
            return true
        end
    end
    return false
end
--
function LGameLanguage:CheckIsShowVie18Tips()
    if self:IsVietnamRegion() then
        local platformId = checknumber(LGameSettings.platformId)
        if platformId == 201 or platformId == 101 then
            return true
        end
    end
    return false
end

--
function LGameLanguage:CheckIsVie119Pack()
    --越南包提审--打开对应的提审需求页面
    if self:IsVietnamRegion() then
        local platformId = checknumber(LGameSettings.platformId)
        if platformId == 119 then
            return true
        end
    end
    
    return false 
end

function LGameLanguage:CheckIsUseConfigControlBindAccount()
    local type = { 2, 3, 4, 5 }
    local result = {}
    local checkPack = checknumber(LIniBoot.platformId)
    for k, v in ipairs(type) do
        local cfg = gModelActivity:GetVerifyConfig(v)
        if cfg then
            local packId = string.split(cfg.packId, ";")
            for _, pack in ipairs(packId) do
                if checknumber(pack) == checkPack then
                    table.insert(result, v)
                end
            end
        end
    end
    return true, result
end
--endregion --------------------------------------------------------------------------------------

function LGameLanguage:GetShieldLHjdRef(refId)
    if not GameTable.ShieldLHjdRef then return end
    return GameTable.ShieldLHjdRef[refId]
end


